#include <stdio.h>
#include <string.h>

void compress(const char *src, char *dst) {
    int j = 0;
    for (int i = 0; src[i]; ++i) {
        if (i == 0 || src[i] != src[i - 1]) {
            dst[j++] = src[i];
        }
    }
    dst[j] = '\0';
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    char s[55], t[55], cs[55], ct[55];
    while (T--) {
        scanf("%s", s);
        scanf("%s", t);
        compress(s, cs);
        compress(t, ct);
        if (strcmp(cs, ct) == 0) {
            printf("Yes\n");
        } else {
            printf("No\n");
        }
    }
    return 0;
}

