#include <bits/stdc++.h>
using namespace std;

string compress(const string &s) {
    string res;
    for (size_t i = 0; i < s.size(); ++i) {
        if (i == 0 || s[i] != s[i - 1]) res.push_back(s[i]);
    }
    return res;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T;
    if (!(cin >> T)) return 0;
    while (T--) {
        string s, t;
        cin >> s >> t;
        cout << (compress(s) == compress(t) ? "Yes" : "No") << '\n';
    }
    return 0;
}

